func (q *Queries) UpsertPrice(ctx context.Context, arg UpsertPriceParams) (Price, error) {
	row := q.db.QueryRow(ctx, upsertPrice,
		arg.PriceListID,
		arg.ProductID,
		arg.Unit,
		arg.MinQuantity,
		arg.Value,
		arg.ValidFrom,
		arg.ValidTo,
	)
	var i Price
	err := row.Scan(
		&i.ID,
		&i.PriceListID,
		&i.ProductID,
		&i.Unit,
		&i.MinQuantity,
		&i.Value,
		&i.ValidFrom,
		&i.ValidTo,
		&i.CreatedAt,
	)
	return i, err
}
